// Compose Solve-event context
const trend = $input.first().json;
const batch = $('MongoDB — Huidige Batch ID').first().json;
const shift = $('ERP — Dienstdoende shift-leider').first().json;

const values = trend.map(t => t.value).slice(0, 30);
const minTemp = Math.min(...values);
const dropDuration = values.filter(v => v < 195).length;

return {
  json: {
    solve_id: 'SOLVE-A',
    batch_id: batch.value,
    current_temp: values[0],
    min_temp_5min: minTemp,
    drift_duration_sec: dropDuration,
    shift_leader: shift.name,
    shift_leader_teams_id: shift.teams_id,
    spec_window: '195-205°C',
    ack_deadline: new Date(Date.now() + 4*60*1000).toISOString(),
    auto_correction: {
      available: true,
      action: 'increase_zone3_setpoint_by_5C',
      reversible: true
    }
  }
};
